class Product:
    def __init__(self, product_id, name, price, quantity,expiry_date):
        self.product_id = product_id
        self.name = name
        self.price = price
        self.quantity = quantity
        self.expiry_date = expiry_date

class FoodProduct(Product):
    def __init__(self, product_id, name, price, quantity, expiry_date):
        super().__init__(product_id, name, price, quantity)


    def check_expiry(self):
        print(self.expiry_date)

    def sell(self):
        if self.quantity > 0:
            self.quantity -= 1

# Do not modify the code below. This function will be called during testing.
def default_test():
    food_product = FoodProduct(product_id=101, name="Apple", price=0.5, quantity=30, expiry_date="2025-5-1")
    print(food_product.product_id)
    print(food_product.name)
    print(food_product.price)
    print(food_product.quantity)
    print(food_product.expiry_date)
    food_product.sell()
    print(food_product.quantity)
    food_product.check_expiry()
